import java.util.*;

public class ComplexityExamples {

    // O(1) — constant: no dependency on n
    static int getFirst(int[] arr) {
        return arr[0]; // one operation regardless of array size
    }

    // O(log n) — binary search: halves search space each step
    static int binarySearch(int[] sorted, int target) {
        int lo = 0, hi = sorted.length - 1;
        while (lo <= hi) {
            int mid = lo + (hi - lo) / 2;
            if (sorted[mid] == target) return mid;
            else if (sorted[mid] < target) lo = mid + 1;
            else hi = mid - 1;
        }
        return -1;
    } // Each iteration: n → n/2 → n/4 → ... → 1 = log₂(n) iterations

    // O(n) — single pass
    static int maxElement(int[] arr) {
        int max = arr[0];
        for (int x : arr) max = Math.max(max, x); // n iterations
        return max;
    }

    // O(n log n) — sorting-based
    static int[] sortedUnique(int[] arr) {
        Arrays.sort(arr); // O(n log n)
        return Arrays.stream(arr).distinct().toArray(); // O(n)
    } // Dominant term: O(n log n)

    // O(n²) — nested loops — WARNING: TLE for large n
    static boolean hasDuplicateBrute(int[] arr) {
        for (int i = 0; i < arr.length; i++)
            for (int j = i+1; j < arr.length; j++)
                if (arr[i] == arr[j]) return true;
        return false;
    }

    // O(n) — same result with HashSet
    static boolean hasDuplicateFast(int[] arr) {
        Set<Integer> seen = new HashSet<>();
        for (int x : arr)
            if (!seen.add(x)) return true; // add returns false on duplicate
        return false;
    }

    // Amortized O(1) — ArrayList add
    static void demonstrateAmortized(int n) {
        List<Integer> list = new ArrayList<>(); // initial capacity 10
        for (int i = 0; i < n; i++) {
            list.add(i); // Usually O(1), occasionally O(n) on resize (doubling)
        }   // Total operations: n + n/2 + n/4 + ... = 2n = O(n) total → O(1) amortized
    }

    public static void main(String[] args) {
        int[] arr = {5, 3, 8, 1, 9, 2, 7, 4, 6};
        int[] sorted = arr.clone(); Arrays.sort(sorted);

        System.out.println("O(1) getFirst: " + getFirst(arr));
        System.out.println("O(log n) bsearch 7: " + binarySearch(sorted, 7));
        System.out.println("O(n) max: " + maxElement(arr));
        System.out.println("O(n²) hasDup brute: " + hasDuplicateBrute(arr));
        System.out.println("O(n)  hasDup fast:  " + hasDuplicateFast(arr));
    }
}

public class RecurrenceDemo {

    /*
     * BINARY SEARCH: T(n) = T(n/2) + O(1)
     * Divide: cut in half  → n/2 subproblem
     * Combine: constant    → O(1)
     * Solution: T(n) = O(log n)
     * Intuition: log₂(10^9) ≈ 30 — only 30 comparisons for 1 billion elements!
     */
    static int binarySearch(int[] a, int t, int lo, int hi) {
        if (lo > hi) return -1;
        int mid = lo + (hi - lo) / 2;  // prevent overflow vs (lo+hi)/2
        if (a[mid] == t) return mid;
        return a[mid] < t ? binarySearch(a, t, mid+1, hi) : binarySearch(a, t, lo, mid-1);
    }
    // One recursive call on HALF the input → log n levels → O(log n)

    /*
     * MERGE SORT: T(n) = 2T(n/2) + O(n)
     * Divide: two halves  → 2 subproblems of size n/2
     * Combine: merge      → O(n)
     * Solution: T(n) = O(n log n)
     * Master theorem: a=2, b=2, f(n)=n → log_b(a)=1 = degree of f(n) → Θ(n log n)
     */
    static void mergeSort(int[] a, int lo, int hi) {
        if (lo >= hi) return;
        int mid = (lo + hi) / 2;
        mergeSort(a, lo, mid);       // T(n/2)
        mergeSort(a, mid+1, hi);     // T(n/2)
        merge(a, lo, mid, hi);       // O(n)
    }
    static void merge(int[] a, int lo, int mid, int hi) {
        int[] tmp = new int[hi - lo + 1];
        int i = lo, j = mid+1, k = 0;
        while (i <= mid && j <= hi)
            tmp[k++] = a[i] <= a[j] ? a[i++] : a[j++];
        while (i <= mid) tmp[k++] = a[i++];
        while (j <= hi)  tmp[k++] = a[j++];
        System.arraycopy(tmp, 0, a, lo, tmp.length);
    }

    public static void main(String[] args) {
        int[] arr = {5,2,8,1,9,3,7,4,6};
        mergeSort(arr, 0, arr.length-1);
        System.out.println(java.util.Arrays.toString(arr)); // sorted
        System.out.println("Found 7 at index: " + binarySearch(arr, 7, 0, arr.length-1));

        // Complexity summary:
        System.out.println("\nComplexity Reference:");
        System.out.println("Binary search: O(log n) — one call on half the input");
        System.out.println("Merge sort:    O(n log n) — two calls + O(n) merge per level");
        System.out.println("log₂(10⁹) ≈ 30 — binary search finds in 30 steps!");
    }
}

problems.description:
Determine the Big-O complexity of these code snippets:

```java
// Snippet 1:
for(int i=0;i<n;i++) for(int j=i;j<n;j++) sum++;
// Snippet 2:
int i=1; while(i<n) i*=2;
// Snippet 3:
for(int i=0;i<n;i++) binarySearch(arr, target);
```

**Answers:** O(n^2), O(log n), O(n log n)

Implement `analyze(String code)` returning the complexity.

