problems.solutionCode:
public class Q3 {
    static int log2(int n) { return (int)(Math.log(n)/Math.log(2)); }

    public static void main(String[] args) {
        int n = 10_000;
        long count2 = (long)n * n;
        long countNlogN = (long)n * log2(n);

        System.out.println("n = " + n);
        System.out.printf("O(n²) ops:      %,d → ~%dms at 1ns/op%n", count2, count2/1_000_000);
        System.out.printf("O(n log n) ops: %,d → ~%dµs at 1ns/op%n", countNlogN, countNlogN/1_000);
        System.out.println();
        System.out.println("Conclusion: O(n²) is 700x more operations than O(n log n) for n=10,000");
        System.out.println("At n=1,000,000: O(n²)=10^12 (~17min), O(n log n)=20M (~20ms)");
    }
}
